 1	import { cacheTag } from 'next/cache';
 2	import { promises as fs } from 'node:fs';
 3	import path from 'node:path';
 4	
 5	export type Post = {
 6	  id: string;
 7	  title: string;
 8	  createdAt: string;
 9	};
10	
11	const POSTS_FILE = path.join(process.cwd(), 'data', 'posts.json');
12	export const POSTS_TAG = 'posts';
13	
14	async function readPostsFile(): Promise<Post[]> {
15	  const raw = await fs.readFile(POSTS_FILE, 'utf8');
16	  return JSON.parse(raw) as Post[];
17	}
18	
19	async function writePostsFile(posts: Post[]) {
20	  await fs.writeFile(POSTS_FILE, JSON.stringify(posts, null, 2) + '\n', 'utf8');
21	}
22	
23	export async function getPosts(): Promise<Post[]> {
24	  'use cache';
25	  cacheTag(POSTS_TAG);
26	
27	  const posts = await readPostsFile();
28	  return posts.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
29	}
30	
31	export async function createPost(title: string): Promise<Post> {
32	  const posts = await readPostsFile();
33	  const post = {
34	    id: crypto.randomUUID(),
35	    title,
36	    createdAt: new Date().toISOString()
37	  };
38	
39	  posts.unshift(post);
40	  await writePostsFile(posts);
41	
42	  return post;
43	}

